-- ============================================
-- Legislacao full-site: geraldo-alckmin / SP ALESP / legislacao_mandato_executivo
-- Seed ampliado parcial: Lote A leis de 2018 sancionadas por Geraldo Alckmin
-- ============================================
-- Fonte oficial: Assembleia Legislativa do Estado de Sao Paulo - Repositorio de Legislacao
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = geraldo-alckmin-sp-alesp-governador-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_sp_alesp_governador_2018_lote_a_20260506
--
-- Filtro factual: paginas oficiais ALESP de 2018 com numero, data, ementa,
-- formula de Governador do Estado de Sao Paulo, assinatura Geraldo Alckmin
-- e Palacio dos Bandeirantes.
-- Nao e inventario completo dos mandatos SP 2001-2018 nem da vida politica.
--
-- Esta migration NAO escreve em projetos_lei.
-- Esta migration NAO escreve em historico_politico.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  lme_total int;
  target_count int;
  mandato_count int;
  projetos_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'geraldo-alckmin';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'geraldo-alckmin: candidato ausente neste banco local/CI minimo; seed LME SP ALESP pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO lme_total
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'geraldo-alckmin-sp-alesp-governador-ampliado-parcial-lote-a-20260506';

  SELECT count(*) INTO projetos_count
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  IF lme_total NOT IN (0, 55) THEN
    RAISE EXCEPTION 'Pre-condicao geraldo-alckmin: esperadas 0 rows atuais ou 55 rows alvo idempotentes em legislacao_mandato_executivo, encontradas %', lme_total;
  END IF;

  IF lme_total = 55 AND target_count <> 55 THEN
    RAISE EXCEPTION 'Pre-condicao geraldo-alckmin: 55 rows existentes, mas apenas % com coverage_id alvo', target_count;
  END IF;

  IF projetos_count <> 100 THEN
    RAISE EXCEPTION 'Pre-condicao geraldo-alckmin: projetos_lei deve permanecer 100 rows Camara ja canonizadas, encontrado %', projetos_count;
  END IF;

  SELECT count(*) INTO mandato_count
  FROM historico_politico hp
  WHERE hp.candidato_id = cand_id
    AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
    AND hp.cargo_canonico = 'Governador'
    AND UPPER(COALESCE(hp.estado, '')) = 'SP'
    AND COALESCE(hp.periodo_inicio, 9999) <= 2018
    AND COALESCE(hp.periodo_fim, 9999) >= 2018;

  IF mandato_count < 1 THEN
    RAISE EXCEPTION 'Pre-condicao geraldo-alckmin: mandato Governador/SP compativel com 2018 nao encontrado em historico_politico';
  END IF;
END $$;

