WITH target AS (
  SELECT
    c.id AS candidato_id,
    seed.*,
    (
      SELECT hp.id
      FROM historico_politico hp
      WHERE hp.candidato_id = c.id
        AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
        AND hp.cargo_canonico = 'Governador'
        AND UPPER(COALESCE(hp.estado, '')) = 'SP'
        AND COALESCE(hp.periodo_inicio, 9999) <= seed.ano
        AND COALESCE(hp.periodo_fim, 9999) >= seed.ano
      ORDER BY hp.periodo_inicio DESC NULLS LAST, hp.id
      LIMIT 1
    ) AS historico_politico_id
  FROM candidatos c
  CROSS JOIN _seed_geraldo_alckmin_sp_alesp_governador_lote_a_lme seed
  WHERE c.slug = 'geraldo-alckmin'
)
INSERT INTO legislacao_mandato_executivo (
  candidato_id,
  historico_politico_id,
  tipo_relacao,
  esfera,
  uf_norma,
  municipio_norma,
  tipo_norma,
  numero,
  ano,
  data_norma,
  ementa,
  signatario,
  autoridade_papel,
  fonte_primaria_url,
  fonte_primaria_titulo,
  fonte_tramitacao_url,
  identificador_fonte,
  metadata
)
SELECT
  target.candidato_id,
  target.historico_politico_id,
  target.tipo_relacao,
  target.esfera,
  target.uf_norma,
  target.municipio_norma,
  target.tipo_norma,
  target.numero,
  target.ano,
  target.data_norma::date,
  target.ementa,
  target.signatario,
  target.autoridade_papel,
  target.fonte_primaria_url,
  target.fonte_primaria_titulo,
  target.fonte_tramitacao_url,
  target.identificador_fonte,
  target.metadata
FROM target
WHERE target.historico_politico_id IS NOT NULL
  AND NOT EXISTS (
    SELECT 1
    FROM legislacao_mandato_executivo lme
    WHERE lme.candidato_id = target.candidato_id
      AND lme.identificador_fonte = target.identificador_fonte
  );

DO $$
DECLARE
  cand_id uuid;
  total_count int;
  scope_count int;
  projetos_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'geraldo-alckmin';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'geraldo-alckmin: pos-condicao pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(*) INTO total_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO scope_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'geraldo-alckmin-sp-alesp-governador-ampliado-parcial-lote-a-20260506'
    AND metadata->>'coverage_scope' = 'inventario_ampliado_parcial_sp_alesp_governador_2018_lote_a_20260506';

  SELECT count(*) INTO projetos_count
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  IF total_count <> 55 THEN
    RAISE EXCEPTION 'Pos-apply geraldo-alckmin: total legislacao_mandato_executivo esperado 55, encontrado %', total_count;
  END IF;

  IF scope_count <> 55 THEN
    RAISE EXCEPTION 'Pos-apply geraldo-alckmin: esperadas 55 rows com coverage_id/scope alvo, encontradas %', scope_count;
  END IF;

  IF projetos_count <> 100 THEN
    RAISE EXCEPTION 'Pos-apply geraldo-alckmin: projetos_lei deve permanecer 100, encontrado %', projetos_count;
  END IF;

  RAISE NOTICE 'Pos-apply geraldo-alckmin SP ALESP Lote A: legislacao_mandato_executivo=% coverage_scope=% projetos_lei=%', total_count, scope_count, projetos_count;
END $$;
